import './BottomSheet.scss';

import { Button } from ':components/Button';
import { Divider } from ':components/Divider';
import { Icon } from ':components/Icon';
import { IconButton } from ':components/IconButton';
import { Typography } from ':components/Typography';
import type { PopupsContextData } from ':helpers';
import { PopupsContext } from ':helpers';
import { classNames } from ':helpers/classnames';
import { useDeviceTouchscreen } from ':helpers/use-device-touchscreen';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import { FloatingPortal } from '@floating-ui/react';
import React, { useContext, useEffect, useRef, useState } from 'react';

import type { BottomSheetProps } from './BottomSheet.types';

export const BottomSheet: React.FC<BottomSheetProps> = ({
	isOpen,
	handleSetOpen,
	modal = true,
	onOutsideClick,
	swiper = false,
	header,
	actions,
	children,
	className,
	style,
	snapPoints = [1],
	initialSnapPoint = 0,
	onClose,
	applicationRootElementID,
	dropdownElementID,
	usePortal = false,
	...rest
}) => {
	const swiperRef = useRef<HTMLDivElement>(null);
	const sheetRef = useRef<HTMLDivElement>(null);
	const headerRef = useRef<HTMLDivElement>(null);
	const contentRef = useRef<HTMLDivElement>(null);
	const initialY = useRef<number>(0);
	const initialHeight = useRef<number>(0);

	const [_snapPoints, _setSnapPoints] = useState<number[]>([]);
	const { isTouchscreen } = useDeviceTouchscreen();

	// Portal logic
	const popupsContext = useContext<PopupsContextData | null>(PopupsContext);
	const [rootElement, setRootElement] = useState<HTMLElement | null>(null);

	const getRootElement = (): HTMLElement => {
		const rootElementId = applicationRootElementID || popupsContext?.applicationElementID;
		const dropdownId = dropdownElementID;

		if (dropdownId) {
			const element = document.getElementById(dropdownId);
			if (element) return element;
		}

		if (rootElementId) {
			const element = document.getElementById(rootElementId);
			if (element) return element;
		}

		return document.body;
	};

	useEffect(() => {
		if (usePortal) {
			setRootElement(getRootElement());
		}
	}, [usePortal, applicationRootElementID, dropdownElementID, popupsContext]);

	const OPENING_DELAY = 200;
	const maxHeight = window.innerHeight;

	if (swiper && !isTouchscreen) {
		console.warn('[dsb_bottomsheet] Swiper недоступен для устройств без тачскрина');
	}

	const convertSnapPoint = (point: number): number => {
		const maxHeightWithOffset = maxHeight - 64;
		if (point <= 1 && point >= 0) {
			return maxHeightWithOffset * point;
		} else if (point < 0) {
			return maxHeightWithOffset + point;
		}
		return point;
	};

	const convertSnapPointsArray = (): void => {
		const requiredSnapPoints = [0];
		const uniqueSnapPoints = [...new Set([...snapPoints, ...requiredSnapPoints])];
		const newSnapPoints = uniqueSnapPoints.map(element => convertSnapPoint(element));

		if (JSON.stringify(newSnapPoints) !== JSON.stringify(_snapPoints)) {
			_setSnapPoints(newSnapPoints);
		}
	};

	useEffect(() => {
		convertSnapPointsArray();
	}, [snapPoints, initialSnapPoint]);

	useEffect(() => {
		if (!swiper || !isTouchscreen) {
			return;
		}

		window.addEventListener('touchstart', swipeStart, { passive: false });
		window.addEventListener('touchmove', swipeMove, { passive: false });
		window.addEventListener('touchend', swipeEnd);
		return () => {
			window.removeEventListener('touchstart', swipeStart);
			window.removeEventListener('touchmove', swipeMove);
			window.removeEventListener('touchend', swipeEnd);
		};
	}, [swiper, isTouchscreen, _snapPoints]);

	useEffect(() => {
		const timeout = setTimeout(() => {
			window.addEventListener('click', handleOutsideClick);
		}, OPENING_DELAY);

		return () => {
			clearTimeout(timeout);
			window.removeEventListener('click', handleOutsideClick);
		};
	}, [isOpen]);

	useEffect(() => {
		if (isOpen) {
			if (sheetRef.current) {
				sheetRef.current.style.height = '0';
			}
			animateTo(convertSnapPoint(snapPoints[initialSnapPoint]));
		} else {
			animateTo(0);
		}
	}, [isOpen]);

	const animateTo = (target: number): void => {
		let start;
		const currentPosition = getHeight();

		const step = (timestamp: number) => {
			if (!start) {
				start = timestamp;
			}
			const progress = Math.min((timestamp - start) / OPENING_DELAY, 1);
			const newPosition = currentPosition + (target - currentPosition) * progress;

			if (sheetRef.current) {
				sheetRef.current.style.height = `${Math.min(newPosition, maxHeight)}px`;
			}

			if (progress < 1) {
				requestAnimationFrame(step);
			}
		};

		requestAnimationFrame(step);
	};

	const closestSnap = (): number => {
		let minDistance = Number.POSITIVE_INFINITY;
		let closestSnapPoint = _snapPoints[0];

		for (const snap of _snapPoints) {
			const distance = Math.abs(getHeight() - snap);
			if (distance < minDistance) {
				minDistance = distance;
				closestSnapPoint = snap;
			}
		}

		if (closestSnapPoint === 0) {
			handleSetOpen(false);
		}

		return closestSnapPoint;
	};

	const getHeight = (): number => (sheetRef.current ? Number.parseInt(sheetRef.current.style.height) || 0 : 0);

	const isScrollable = (ref: React.RefObject<HTMLElement>): boolean =>
		ref.current ? ref.current.scrollHeight > ref.current.clientHeight : false;

	const isScrollElement = (event: TouchEvent): boolean => {
		const path = event.composedPath();
		const onSwiper = swiperRef.current && path.includes(swiperRef.current);
		const onHeader = headerRef.current && path.includes(headerRef.current);
		const onContent = contentRef.current && path.includes(contentRef.current);
		const isContentScrollable = isScrollable(contentRef);

		return onSwiper || onHeader || (onContent && !isContentScrollable);
	};

	const swipeStart = (event: TouchEvent): void => {
		initialY.current = event.touches[0].clientY;
		initialHeight.current = getHeight();
	};

	const swipeMove = (event: TouchEvent): void => {
		if (!isScrollElement(event)) {
			return;
		}

		const endY = event.touches[0].clientY;
		const diff = initialY.current - endY;
		const newHeight = initialHeight.current + diff;
		if (sheetRef.current) {
			sheetRef.current.style.height = `${Math.min(Math.max(newHeight, 0), maxHeight)}px`;
		}
	};

	const swipeEnd = (event: TouchEvent): void => {
		animateTo(closestSnap());
	};

	const handleOutsideClick = (event: Event): void => {
		if (sheetRef.current?.contains(event.target as Node)) {
			return;
		}
		if (isOpen) {
			onOutsideClick?.(event);
		}
	};

	const CloseButton = () => (
		<IconButton
			onClick={event => {
				if (onClose) {
					onClose?.(event as unknown as Event);
				} else {
					handleSetOpen(false);
				}
			}}
			size="large"
			iconName={Icons.Close}
		/>
	);

	const ActionButton = () => (
		<Typography
			variant="subtitle3"
			className="dsb_bottomsheet__header-action-button"
			onClick={header?.actionButton.onClick}
		>
			{header?.actionButton.label}
		</Typography>
	);

	const bottomSheetContent = (
		<>
			{modal && isOpen && <div className="dsb_bottomsheet__modal" />}
			<div
				aria-modal
				role="dialog"
				data-testid="BottomSheet"
				className={classNames('dsb_bottomsheet', className)}
				ref={sheetRef}
				style={style}
				{...rest}
			>
				{swiper && isTouchscreen && (
					<div className="dsb_bottomsheet__swiper" ref={swiperRef}>
						<div className="dsb_bottomsheet__swiper-trumb" />
					</div>
				)}

				{header && (
					<>
						<div className="dsb_bottomsheet__header" ref={headerRef}>
							{((header.closeButton && header.actionButton) || header?.icon) && (
								<div className="dsb_bottomsheet__header-icon">
									{header.closeButton && header.actionButton ? (
										<CloseButton />
									) : (
										header?.icon && <Icon size="large" iconName={header?.icon} />
									)}
								</div>
							)}
							<div className="dsb_bottomsheet__header-headings">
								<Typography variant="body1" className="dsb_bottomsheet__header-headings-title">
									{header?.title}
								</Typography>
								<Typography variant="body3" className="dsb_bottomsheet__header-headings-subtitle">
									{header?.subtitle}
								</Typography>
							</div>
							<div className="dsb_bottomsheet__header-action">
								{header.closeButton && header.actionButton ? (
									<ActionButton />
								) : (
									(header.closeButton && <CloseButton />) || (header.actionButton && <ActionButton />)
								)}
							</div>
						</div>
						{header?.divider && <Divider />}
					</>
				)}

				<div className="dsb_bottomsheet__content" ref={contentRef}>
					{children}
				</div>

				{actions && (
					<div className="dsb_bottomsheet__actionbar-wrapper">
						<Divider />
						<div className="dsb_bottomsheet__actionbar">
							{actions?.map((button, index) => (
								<Button
									key={index}
									variant={button?.variant}
									onClick={button?.onClick}
									size="medium"
									className="dsb_bottomsheet__actionbar-button"
								>
									{button?.label}
								</Button>
							))}
						</div>
					</div>
				)}
			</div>
		</>
	);

	if (usePortal && rootElement) {
		return <FloatingPortal root={rootElement}>{bottomSheetContent}</FloatingPortal>;
	}

	return bottomSheetContent;
};

export type { BottomSheetProps };
